const response = await fetch("https://api.extole.io/events", {
  method: "POST",
  headers: {
    "Authorization": "Bearer YOUR_ACCESS_TOKEN",
    "Content-Type": "application/json",
    "Accept": "application/json"
  },
  body: JSON.stringify({ event_name: "advocate_share", email: "friend@example.com" })
});
const result = await response.json();
console.log(result.id);

const params = new URLSearchParams({ access_token: "YOUR_ACCESS_TOKEN", email: "friend@example.com" });
const response = await fetch(`https://api.extole.io/events/advocate_share?${params}`, {
  headers: { "Accept": "application/json" }
});
const result = await response.json();
console.log(result.id);

